import { random } from "@/lib/support/number";

function range(start: number = 0, end?: number, step: number = 1) {
  if (end === undefined) {
    end = start;
    start = 0;
  }

  if (step === 0) {
    step = 1;
  }

  step = start > end && step > 0 ? step * -1 : step;

  const length = Math.floor((end - start) / step) + 1;

  return Array.from({ length }, (_, i) => start + i * step);
}

function unique<TArray>(array: TArray[]) {
  return [...new Set(array)];
}

function replace<TArray>(array: TArray[], index: number, value: TArray) {
  array[index] = value;
  return array;
}

function sample<TArray>(array: TArray[]) {
  return array[random(array.length)];
}

function sum(array: number[]) {
  let total = 0;
  array.forEach(e => (total += e));
  return total;
}

function chunk<TArray>(array: TArray[], size: number) {
  let chunkedNumber = 0;
  const chunkedArray: unknown[] = [];
  array.forEach(() => {
    if (chunkedNumber === array.length)
      return;

    const slicedArray = array.slice(chunkedNumber, chunkedNumber + size);
    if (slicedArray.length === 0)
      return;
    chunkedArray.push(slicedArray);
    chunkedNumber += size;
  });

  return chunkedArray;
}

function compact<TArray>(array: TArray[]) {
  return array.filter(e => e);
}

function difference<T>(
  firstArray: T[],
  secondArray: T[],
) {
  return firstArray.filter(f => !secondArray.includes(f));
}

function remove<TArray>(array: TArray[], value: TArray) {
  const index = array.indexOf(value);
  if (index === -1)
    return array;
  array.splice(index, 1);
  return array;
}

function shuffle<TArray>(array: TArray[]) {
  let currentIndex = array.length;
  while (currentIndex !== 0) {
    const randomIndex = random(0, currentIndex);
    currentIndex--;

    const temp = array[currentIndex];
    array[currentIndex] = array[randomIndex]!;
    array[randomIndex] = temp!;
  }
  return array;
}

function head<TArray>(array: TArray[]) {
  return array[0];
}

function last<TArray>(array: TArray[]) {
  return array[array.length - 1];
}

function nth<TArray>(array: TArray[], n: number) {
  return array[n];
}

function intersection<T>(
  firstArray: T[],
  secondArray: T[],
): T[] {
  return firstArray.filter(e => secondArray.includes(e));
}

function tail<TArray>(array: TArray[]) {
  array.shift();
  return array;
}

function take<TArray>(array: TArray[], n: number = 0) {
  return array.slice(0, n);
}

function union<TFirstArray, TSecondArray>(
  firstArray: TFirstArray[],
  secondArray: TSecondArray[],
) {
  return [...new Set([...firstArray, ...secondArray])];
}

export {
  chunk,
  compact,
  difference,
  head,
  intersection,
  last,
  nth,
  range,
  remove,
  replace,
  sample,
  shuffle,
  sum,
  tail,
  take,
  union,
  unique,
};

import { fileSystem } from "@/lib/support/file-system";
import { log } from "@/lib/support/log";
import { basePath } from "@/lib/support/path";

type GenerateType = {
  filePath: string;
  mime?: string;
};

type ReplacePathStupType = GenerateType & {
  stubPath: string;
  replaceParameters: Record<string, string>;
};

async function generate({ filePath, mime = "tsx" }: GenerateType) {
  const fileLocation = `${filePath}.${mime}`;

  if (await fileSystem.pathExists(fileLocation)) {
    log(`file ${basePath(fileLocation)} already exsists.`, "red");
    process.exit(1);
  }

  log(`creating on :  ${basePath(fileLocation)}`, "green");
  await fileSystem.createFile(fileLocation);
}

async function generateWithStub({
  filePath,
  mime = "tsx",
  stubPath,
  replaceParameters,
}: ReplacePathStupType) {
  const fileLocation = `${filePath}.${mime}`;

  if (!(await fileSystem.pathExists(stubPath))) {
    log(`stub path : ${stubPath} : not exists.`, "red");
    process.exit(1);
  }

  if (await fileSystem.pathExists(fileLocation)) {
    log(`${basePath(fileLocation)} already exsists.`, "red");
    process.exit(1);
  }

  let stub = await fileSystem.get(stubPath);

  for (const [key, value] of Object.entries(replaceParameters)) {
    stub = stub.toString().replaceAll(key, value);
  }

  log(`creating on :  ${basePath(fileLocation)}`, "green");
  await fileSystem.write(fileLocation, stub);
}

export { generate, generateWithStub };

type colorType
  = | "red"
    | "green"
    | "yellow"
    | "blue"
    | "magenta"
    | "cyan"
    | "white"
    | "brightRed"
    | "brightGreen"
    | "brightYellow"
    | "brightBlue"
    | "brightMagenta"
    | "brightCyan"
    | "gray"
    | "orange";

const COLOR_MAP: Record<colorType, string> = {
  red: "\x1B[31m",
  green: "\x1B[32m",
  yellow: "\x1B[33m",
  blue: "\x1B[34m",
  magenta: "\x1B[35m",
  cyan: "\x1B[36m",
  white: "\x1B[37m",
  gray: "\x1B[90m",
  brightRed: "\x1B[91m",
  brightGreen: "\x1B[92m",
  brightYellow: "\x1B[93m",
  brightBlue: "\x1B[94m",
  brightMagenta: "\x1B[95m",
  brightCyan: "\x1B[96m",
  orange: "\x1B[38;5;208m",
};

const RESET = "\x1B[0m";

function getColorString(colorName: colorType) {
  return COLOR_MAP[colorName];
}

function log<T>(message: T, colorName: colorType = "white") {
  const color = getColorString(colorName);
  process.stdout.write(`${color}`);
  console.dir(message, { depth: null, colors: true });
  process.stdout.write(`${RESET}\n`);
}

export { log };

const SPECIAL_CHARECTERS = `!"#$%&'()*+,-./:;<=>?@[\\]^_\`{|}~`;
const SPECIAL_CHARECHTER_REGEX = /[\s!"#$%&'()*+,\-./:;<=>?@[\\\]^_`{|}~]+|(?=[A-Z])/;

function after(text: string, value: string): string {
  const index = text.indexOf(value);

  if (index === -1)
    return "";
  return text.slice(index + value.length);
}

function append(text: string, appendedString: string) {
  if (appendedString.length === 0)
    return text;

  return text + appendedString;
}

function before(text: string, value: string): string {
  const index = text.indexOf(value);

  if (index === -1)
    return "";
  return text.slice(0, index);
}

function between(text: string, firstValue: string, secondValue: string): string {
  return text.slice(text.indexOf(firstValue) + firstValue.length, text.indexOf(secondValue));
}

function trim(text: string, characters: string): string {
  if (!text || !characters)
    return text;
  const escaped = characters.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const regex = new RegExp(`^[${escaped}]+|[${escaped}]+$`, "g");

  return text.replace(regex, "");
}

function camel(text: string): string {
  return text
    .split(SPECIAL_CHARECHTER_REGEX)
    .map((str, index) => (index === 0 ? str.toLowerCase() : capitalize(str)))
    .join("");
}

function capitalize(text: string): string {
  return text.charAt(0).toUpperCase() + text.slice(1);
}

function headline(text: string): string {
  return text.split(/(?<!^)(?=[A-Z])|[_\-\s]+/g).map(str => capitalize(str)).join(" ");
}

function kebab(text: string): string {
  return text
    .replace(/([a-z0-9])([A-Z])|[_\s]+/g, (_, a, b) => a && b ? `${a}-${b}` : "-")
    .toLowerCase();
}

function lowerCaseFirst(text: string): string {
  return text.charAt(0).toLowerCase() + text.slice(1);
}

function limit(text: string, length: number, appendedString: string = "..."): string {
  return text.length > length ? text.slice(0, length).concat(appendedString) : text;
}

function mask(text: string, paddingCharacter: string = "*", length: number) {
  return text.slice(0, length) + paddingCharacter.repeat(text.length - length);
}

function pad(text: string, length: number, paddingCharacter: string = " ", direction: "pad-center" | "pad-left" | "pad-right" = "pad-center") {
  const textLength = text.length;

  if (text.length >= length)
    return text;

  const totalPadding = length - textLength;
  const leftPadding = Math.floor(totalPadding / 2);
  const rightPadding = totalPadding - leftPadding;

  switch (direction) {
    case "pad-center" :
      return paddingCharacter.repeat(leftPadding) + text + paddingCharacter.repeat(rightPadding);
    case "pad-left" :
      return paddingCharacter.repeat(totalPadding) + text;
    case "pad-right" :
      return text + paddingCharacter.repeat(totalPadding);
  }
}

function random(length: number, characters = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789"): string {
  let result = "";

  for (let i = 0; i < length; i++) {
    result += characters.charAt(Math.floor(Math.random() * characters.length));
  }

  return result;
}

function slug(text: string, character: string = "-") {
  return text
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036F]/g, "")
    .trim()
    .replace(/[^a-z0-9 -]/g, "")
    .replace(/\s+/g, character)
    .replace(/-+/g, "-");
}

function squish(text: string) {
  return text.replace(/\s+/g, " ").trim();
}

function snake(text: string): string {
  return text
    .replace(/([a-z0-9])([A-Z])/g, "$1_$2")
    .replace(/[\s-]+/g, "_")
    .toLowerCase();
}

function studly(text: string): string {
  return text
    .replace(/[_\-\s]+(.)?/g, (_, c) => (c ? c.toUpperCase() : ""))
    .replace(/^(.)/, c => c.toUpperCase());
}

function swap(object: Record<string, string>, text: string): string {
  let result = text;

  for (const [key, value] of Object.entries(object)) {
    result = result.replaceAll(key, value);
  }

  return result;
}

function uuid(): string {
  const now = Date.now();
  const timeHex = now.toString(16).padStart(12, "0");

  const random = crypto.getRandomValues(new Uint8Array(10));
  const randomHex = [...random].map(b => b.toString(16).padStart(2, "0")).join("");

  return (
    `${timeHex.slice(0, 8)}-${
      timeHex.slice(8, 12)}-7${
      randomHex.slice(0, 3)}-${
      ((Number.parseInt(randomHex.charAt(3), 16) & 0x3) | 0x8).toString(16)
    }${randomHex.slice(4, 7)}-${
      randomHex.slice(7)}`
  );
}

function title(text: string): string {
  return text
    .toLowerCase()
    .replace(/\b\p{L}/gu, char => char.toUpperCase());
}

function upperCaseFirst(text: string): string {
  return text.charAt(0).toUpperCase() + text.slice(1);
}

function wordCount(text: string): number {
  return text.trim().split(/\s+/).length;
}

function truncate(text: string, length: number = 20, omission: string = "...") {
  return text.length > length ? `${text.slice(0, length)}${omission}` : text;
}

const str = {
  after,
  append,
  before,
  between,
  trim,
  camel,
  capitalize,
